const main = require('../../lib/jibo-emotion-system');

const EmotionSystem = main.emotionSystem.EmotionSystem;
const EmotionSpace = main.emotion.EmotionSpace;
const EmotionTrace = main.emotion.EmotionTrace;
const EmotionPoint = main.common.EmotionPoint;
const EmotionName = main.common.EmotionName;
const jibo = require('../../../jibo');

let clock, es;

describe('EmotionSpace', () => {

    beforeEach((done) => {
        clock = sinon.useFakeTimers();
        es = new EmotionSystem();
        es.init({
            jibo: jibo
        });
        done();
    });

    afterEach(() => {
        clock.restore();
        es.dispose();
    });


    it('should decay emotions back to neutral after an hour.', (done) => {
        const emoSpace = new EmotionSpace(es);
        emoSpace.setInterval = setInterval.bind(this);
        emoSpace.clearInterval = clearInterval.bind(this);
        emoSpace.init(es.emotions);
        const happyTrace = {
            emotionalImpact: new EmotionPoint(1, 0)
        };
        emoSpace.update(happyTrace);
        let resultA = emoSpace.getNearestEmotion();
        expect(resultA.name).to.equal(EmotionName.PLEASED);
        clock.tick(60 * 1000);
        let resultB = emoSpace.getNearestEmotion();
        expect(resultB.name).to.equal(EmotionName.NEUTRAL);
        emoSpace.dispose();
        done();
    });

    it('should reset to neutral', () => {
        const emoSpace = new EmotionSpace(es);
        emoSpace.init(es.emotions);
        const happyTrace = {
            emotionalImpact: new EmotionPoint(1, 0)
        };
        emoSpace.update(happyTrace);
        let resultA = emoSpace.getNearestEmotion();
        expect(resultA.name).to.equal(EmotionName.PLEASED);
        emoSpace._resetToNeutral();
        let neutralEmo = emoSpace.getNearestEmotion();
        let neutralVals = emoSpace.getCurrentPosition();
        expect(neutralEmo.name).to.equal(EmotionName.NEUTRAL);
        expect(neutralVals.valence).to.be.closeTo(0.45, 0.01);
        expect(neutralVals.confidence).to.be.closeTo(0.2, 0.01);
    });

    describe('#getNearestEmotion', () => {
        it('should find the nearest emotion given a reference point.', () => {
            let positionA = new EmotionPoint(0.8, 0);
            let resultA = es._emotionSpace.getNearestEmotion(positionA);
            expect(resultA.name).to.equal(EmotionName.PLEASED);
            let positionB = new EmotionPoint(0, -.9);
            let resultB =  es._emotionSpace.getNearestEmotion(positionB);
            expect(resultB.name).to.equal(EmotionName.UNCERTAIN);
            let resultC =
                es._emotionSpace.getNearestEmotion(new EmotionPoint(0.1, 0));
            expect(resultC.name).to.equal(EmotionName.NEUTRAL);
        });
    });

    describe('#Events', () => {
        it('should emit change events.', (done) => {
            const spy = sinon.spy();
            sinon.stub(jibo.action, 'getState', () => {
                return {
                    sleep: 'AWAKE',
                    time: new Date()
                };
            });
            sinon.stub(jibo.action, 'addPlayAnimationGoal', function(data) {
                jibo.action.addPlayAnimationGoal.restore()
                 jibo.action.getState.restore()
                expect(data.category).to.equal('laughing');
                done();
            });
            es.events.emotionChanged.on((lastEmotion) => {
                spy(lastEmotion);
            });
            const impact = new EmotionTrace(null, null, new EmotionPoint(1, 1));
            es._emotionSpace.update(impact);

            const eventImpact = spy.getCall(0).args[0];
            expect(eventImpact.emotionValues.valence).to.equal(1);
            expect(eventImpact.emotionValues.confidence).to.equal(1);
            expect(eventImpact.name).to.equal("JOYFUL");
        });
    });
});
